/* ============================================================
   Context + hook
   ============================================================ */
const LangContext = createCtxI18n({ lang: "en", setLang: () => {}, t: (k) => k });

function LangProvider({ children }) {
  const [lang, setLangState] = useStateI18n(() => {
    try { return localStorage.getItem("apirental.lang") || "en"; } catch (e) { return "en"; }
  });
  const setLang = (code) => {
    setLangState(code);
    try { localStorage.setItem("apirental.lang", code); } catch (e) {}
    document.documentElement.lang = code;
  };
  useEffectI18n(() => { document.documentElement.lang = lang; }, [lang]);

  const dict = T[lang] || T.en;
  const t = (key, vars) => {
    let s = (dict[key] != null ? dict[key] : (T.en[key] != null ? T.en[key] : key));
    if (vars) for (const k in vars) s = s.split("{" + k + "}").join(vars[k]);
    return s;
  };
  // expose for non-component helpers
  window.__t = t; window.__lang = lang;

  return React.createElement(LangContext.Provider, { value: { lang, setLang, t } }, children);
}

function useT() { return useCtxI18n(LangContext); }

/* translate stored English value via key-maps */
function txCat(t, v) { return CAT_KEY[v] ? t(CAT_KEY[v]) : v; }
function txTag(t, v) { return v && TAG_KEY[v] ? t(TAG_KEY[v]) : v; }
function txStatus(t, v) { return STATUS_KEY[v] ? t(STATUS_KEY[v]) : v; }

/* additional value maps for admin / locations */
const FUEL_KEY = { "Petrol": "fuel.petrol", "Hybrid": "fuel.hybrid", "Electric": "fuel.electric", "Diesel": "fuel.diesel" };
const TIER_KEY = { "Platinum": "tier.platinum", "Gold": "tier.gold", "Silver": "tier.silver", "Bronze": "tier.bronze" };
const BSTATUS_KEY = { "All": "bst.all", "Active": "bst.active", "Upcoming": "bst.upcoming", "Completed": "bst.completed", "Cancelled": "bst.cancelled" };
const LOC_KEY = {
  "Athens Downtown Flagship": "loc.ath-dt.name", "Athens International Airport": "loc.ath-air.name", "Athens Marina Bay": "loc.ath-marina.name", "Athens Old Town Garage": "loc.ath-old.name",
  "Thessaloniki Downtown Flagship": "loc.thes-dt.name", "Thessaloniki International Airport": "loc.thes-air.name", "Thessaloniki Waterfront Marina": "loc.thes-marina.name", "Thessaloniki Old Town Garage": "loc.thes-old.name",
};
const CITY_KEY = { "Athens": "loc.city.athens", "Thessaloniki": "loc.city.thessaloniki" };
function txFuel(t, v) { return FUEL_KEY[v] ? t(FUEL_KEY[v]) : v; }
function txTier(t, v) { return TIER_KEY[v] ? t(TIER_KEY[v]) : v; }
function txBStatus(t, v) { return BSTATUS_KEY[v] ? t(BSTATUS_KEY[v]) : v; }
function txLoc(t, v) { return LOC_KEY[v] ? t(LOC_KEY[v]) : v; }
function txCity(t, v) { return CITY_KEY[v] ? t(CITY_KEY[v]) : v; }

Object.assign(window, { T, LangContext, LangProvider, useT, txCat, txTag, txStatus, txFuel, txTier, txBStatus, txLoc, txCity, FUEL_KEY, TIER_KEY, BSTATUS_KEY, LOC_KEY, CITY_KEY });
